const csvData = $json.data || '';

if (!csvData || csvData.trim().length === 0) {
  console.log('⚠️ No data returned from API');
  return [];
}

// --- CSV parsing helpers ---
function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false;
  let current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];

    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }

    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }

    current += c;
  }

  vals.push(current);
  return vals.map(v => v.trim());
}

// --- Parse CSV ---
const lines = csvData.trim().split(/\r?\n/);
const headers = parseCSVLine(lines[0]);

console.log('📊 Headers:', headers);

// Try to find the open opps any_time column (Backstory uses friendly names)
const openOppHeader = headers.find(h =>
  h.toLowerCase().includes('open') &&
  h.toLowerCase().includes('opportun') &&
  h.toLowerCase().includes('any')
);

if (!openOppHeader) {
  console.log('⚠️ Could not find Open Opportunities (Any Time) column');
}

// --- Build account objects ---
const parsedAccounts = [];

for (let i = 1; i < lines.length; i++) {
  const vals = parseCSVLine(lines[i]);
  if (vals.length !== headers.length) continue;

  const account = {};
  headers.forEach((h, idx) => {
    account[h] = vals[idx] || '';
  });

  parsedAccounts.push(account);
}

console.log(`✅ Parsed ${parsedAccounts.length} accounts from CSV`);

// --- Filter out accounts with open opps > 0 ---
function toNumber(x) {
  const n = Number(String(x || '').replace(/,/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const kept = [];
const removed = [];

for (const acc of parsedAccounts) {
  const rawOpenOpps = openOppHeader ? acc[openOppHeader] : null;
  const openOpps = toNumber(rawOpenOpps);

  if (openOpps > 0) {
    removed.push({
      accountName: acc['Account Name'] || acc['ootb_account_name'],
      openOpps
    });
    continue;
  }

  kept.push(acc);
}

console.log('🧹 Filter results:', {
  totalParsed: parsedAccounts.length,
  keptNoOpenOpps: kept.length,
  removedWithOpenOpps: removed.length,
  removedSample: removed.slice(0, 10)
});

// --- Output ---
return kept.map(a => ({ json: a }));

/**
 * Extract Account Data - Run Once for All Items
 */

const items = $input.all();
console.log(`🔍 Extract Account Data: Processing ${items.length} items`);

// Helper to find header key (case-insensitive)
function findHeader(obj, keywords) {
  const keys = Object.keys(obj);
  for (const keyword of keywords) {
    const found = keys.find(k => 
      k.toLowerCase().includes(keyword.toLowerCase())
    );
    if (found) return found;
  }
  return null;
}

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // Debug: Log keys from first item
  if (i === 0) {
    console.log('📋 Available keys:', Object.keys(item).slice(0, 15).join(', '));
  }

  // Extract account ID (CRM ID, not Owner ID!)
  const accountId = item.ootb_account_id || 
                    item['Account ID'] || 
                    findHeader(item, ['account_id', 'crm_id']) || 
                    'Unknown';

  // Extract account name
  const accountName = item['Account Name'] || 
                      item.ootb_account_name || 
                      findHeader(item, ['account_name', 'name']) || 
                      'Unknown';

  // 🔥 CRITICAL: Extract account owner NAME (not ID!)
  const accountOwner = item['Account Owner (name)'] ||  // ✅ Primary source
                       item.ootb_account_original_owner || 
                       item.account_original_owner ||
                       findHeader(item, ['owner', 'account owner']) ||
                       'Unassigned';

  // Extract engagement level
  const engagementLevel = parseFloat(item['Account Engagement Level']) || 
                         parseFloat(item.ootb_account_engagement_level) || 
                         0;

  // Extract Backstory ID
  const peopleaiId = item['People.ai Internal ID'] || 
                     item.ootb_account_people_internal_id ||
                     null;

  console.log(`✅ Account ${i}: "${accountName}" → Owner: "${accountOwner}" (ID: ${accountId})`);

  results.push({
    json: {
      accountId: accountId,
      accountName: accountName,
      accountOwner: accountOwner,  // 🔥 Now extracts NAME not ID
      engagementLevel: engagementLevel,
      peopleaiId: peopleaiId,
      raw: item
    }
  });
}

console.log(`✅ Extracted ${results.length} accounts with owners`);

return results;

/**
 * Parse AI Response - Fixed to Preserve Account Metadata
 * EXCLUDE: Accounts with "No revenue/sales opportunity signals detected"
 */

const items = $input.all();
console.log(`✅ Parse AI Response: Processing ${items.length} items`);

const results = [];
let excludedNoSignals = 0;

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const aiOutput = item.output || item.aiOutput || '';

  // ✅ USE the accountName and accountOwner that were passed through!
  const accountName = item.accountName || 'Unknown Account';
  const accountOwner = item.accountOwner || 'Unassigned';

  console.log(`\n📊 Processing account: "${accountName}" (Owner: ${accountOwner})`);
  console.log(`AI Output length: ${aiOutput.length} chars`);

  // 🚫 CRITICAL: Check for "No revenue" signal
  if (/no revenue.*signal/i.test(aiOutput) || 
      /no.*sales.*opportunity.*signal/i.test(aiOutput)) {
    console.log(`🚫 EXCLUDED: ${accountName} - No revenue signals detected`);
    excludedNoSignals++;
    continue;  // Skip this account
  }

  // Check if AI detected a signal (look for key phrases)
  const hasSignal = /SIGNAL_DETECTED.*?true/i.test(aiOutput) ||
                    /POSITIVE SIGNALS DETECTED/i.test(aiOutput) ||
                    /BUYING SIGNAL/i.test(aiOutput);

  if (!hasSignal) {
    console.log(`⚠️ No signal detected for ${accountName}`);
    continue;  // Skip this account
  }

  // Extract signals (look for bullet points after SIGNALS: section)
  const signals = [];

  // Pattern 1: **SIGNALS:** followed by bullet points
  const signalsMatch = aiOutput.match(/\*\*SIGNALS:\*\*\s*([\s\S]*?)(?=\n\*\*|$)/i);
  if (signalsMatch) {
    const signalsText = signalsMatch[1];
    const bulletPoints = signalsText.split('\n')
      .map(s => s.trim())
      .filter(s => s.startsWith('-') || s.startsWith('•') || s.startsWith('**'))
      .map(s => s.replace(/^[-•]\s*/, '').replace(/^\*\*/, '').replace(/\*\*$/, '').trim());
    signals.push(...bulletPoints);
  }

  // Pattern 2: Look for common signal keywords in the text
  if (signals.length === 0) {
    const text = aiOutput.toLowerCase();
    if (text.includes('executive engagement') || text.includes('executive signal')) {
      signals.push('Executive engagement');
    }
    if (text.includes('budget') || text.includes('pricing')) {
      signals.push('Budget discussions');
    }
    if (text.includes('timeline') || text.includes('deadline')) {
      signals.push('Timeline pressure');
    }
    if (text.includes('demo') || text.includes('poc')) {
      signals.push('POC/Demo scheduled');
    }
    if (text.includes('urgent') || text.includes('asap')) {
      signals.push('Urgent requirements');
    }
  }

  // Extract recommendation
  let recommendation = '';
  const recMatch = aiOutput.match(/\*\*RECOMMENDATION:\*\*\s*([\s\S]*?)(?=\n\*\*|$)/i);
  if (recMatch) {
    recommendation = recMatch[1].trim();
  } else {
    // Try to extract first actionable sentence
    const actionMatch = aiOutput.match(/(?:Schedule|Prioritize|Focus on|Address|Prepare)[^.]+\./i);
    if (actionMatch) {
      recommendation = actionMatch[0];
    }
  }

  // Extract confidence
  let confidence = 'medium';
  const confMatch = aiOutput.match(/\*\*CONFIDENCE:\*\*\s*(\w+)/i);
  if (confMatch) {
    confidence = confMatch[1].toLowerCase();
  } else if (aiOutput.toLowerCase().includes('strong') || aiOutput.toLowerCase().includes('high confidence')) {
    confidence = 'high';
  }

  console.log(`✅ Extracted ${signals.length} signals for ${accountName}`);
  console.log(`Signals: ${signals.join(', ')}`);
  console.log(`Recommendation: ${recommendation.substring(0, 100)}...`);

  results.push({
    json: {
      // ✅ KEEP the original account metadata - DON'T extract from AI output!
      accountName: accountName,
      accountOwner: accountOwner,
      accountId: item.accountId,
      engagementLevel: item.engagementLevel,
      peopleaiId: item.peopleaiId,

      // Extracted from AI analysis
      signals: signals,
      recommendation: recommendation,
      confidence: confidence,

      // Keep original AI output for reference
      context: aiOutput,

      // Keep raw data
      raw: item.raw
    }
  });
}

console.log(`\n✅ Parsed ${results.length} AI responses with signals (from ${items.length} total)`);
console.log(`🚫 Excluded ${excludedNoSignals} accounts with 'No revenue signals'`);

return results;

/**
 * Date Range (Last Week) — NO luxon required
 *
 * Produces:
 * - startOfLastWeek / endOfLastWeek (ISO strings)
 * - startOfLastWeekTimestamp / endOfLastWeekTimestamp (epoch ms)
 * - weekLabel (human-readable)
 *
 * Definition: "last full week" Monday 00:00:00.000 -> Sunday 23:59:59.999
 * Uses the server's local timezone.
 */

const now = new Date();
const clone = (d) => new Date(d.getTime());

// Start of today
const today = clone(now);
today.setHours(0, 0, 0, 0);

// Start of this week (Monday 00:00)
const startOfThisWeek = clone(today);
const day = startOfThisWeek.getDay(); // 0=Sun..6=Sat
const diffToMonday = day === 0 ? -6 : 1 - day;
startOfThisWeek.setDate(startOfThisWeek.getDate() + diffToMonday);

// Start of last week
const startOfLastWeek = clone(startOfThisWeek);
startOfLastWeek.setDate(startOfLastWeek.getDate() - 7);

// End of last week (Sunday 23:59:59.999)
const endOfLastWeek = clone(startOfThisWeek);
endOfLastWeek.setMilliseconds(-1);

// Label (e.g., "Week of Dec 8–Dec 14")
const fmt = (d) =>
  d.toLocaleDateString("en-US", { month: "short", day: "numeric" });

return [
  {
    json: {
      startOfLastWeek: startOfLastWeek.toISOString(),
      endOfLastWeek: endOfLastWeek.toISOString(),
      startOfLastWeekTimestamp: startOfLastWeek.getTime(),
      endOfLastWeekTimestamp: endOfLastWeek.getTime(),
      weekLabel: `Week of ${fmt(startOfLastWeek)}–${fmt(endOfLastWeek)}`,
    },
  },
];

