/**
 * Parse New Opps CSV
 *
 * Handles Backstory export responses where:
 *  - $json.data is the CSV string (MOST COMMON in your screenshot)
 *  - OR $json.data.content is CSV
 *  - OR $json.body is CSV
 *  - OR $json is already the CSV string
 *
 * Outputs ONE item:
 * {
 *   opportunities: [ { accountName, owner, amount, type, stage, createdDate, closeDate, peopleaiId, raw } ... ],
 *   accountsWithNewOppsLastWeek: [ ... ],
 *   totals: { count, amount }
 * }
 */

// ---------- helpers ----------
function toNumber(x) {
  const n = Number(String(x ?? "").replace(/[$,]/g, ""));
  return Number.isFinite(n) ? n : 0;
}

// Simple CSV parser with quote support
function parseCSV(text) {
  const rows = [];
  let row = [];
  let cur = "";
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    const next = text[i + 1];

    if (c === '"') {
      if (inQuotes && next === '"') {
        // escaped quote
        cur += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (!inQuotes && c === ",") {
      row.push(cur);
      cur = "";
      continue;
    }

    if (!inQuotes && c === "\n") {
      row.push(cur);
      rows.push(row);
      row = [];
      cur = "";
      continue;
    }

    if (!inQuotes && c === "\r") {
      // ignore CR (windows newlines)
      continue;
    }

    cur += c;
  }

  // last cell
  row.push(cur);
  rows.push(row);

  // drop empty trailing row
  if (rows.length && rows[rows.length - 1].every(v => String(v ?? "").trim() === "")) {
    rows.pop();
  }

  return rows;
}

function getField(rowObj, ...keys) {
  for (const k of keys) {
    if (rowObj[k] != null && String(rowObj[k]).trim() !== "") return rowObj[k];
  }
  return "";
}

// ---------- read CSV text from input ----------
const j = $input.first()?.json || {};

// IMPORTANT: your actual payload is { data: "<csv>" }
const csvText =
  (typeof j.data === "string" && j.data) ? j.data :
  (typeof j?.data?.content === "string" && j.data.content) ? j.data.content :
  (typeof j.body === "string" && j.body) ? j.body :
  (typeof j === "string" && j) ? j :
  "";

// If empty, return empty structure (but don't throw)
if (!csvText || typeof csvText !== "string") {
  return [{
    json: {
      opportunities: [],
      accountsWithNewOppsLastWeek: [],
      totals: { count: 0, amount: 0 }
    }
  }];
}

// ---------- parse CSV ----------
const rows = parseCSV(csvText);
if (!rows.length) {
  return [{
    json: {
      opportunities: [],
      accountsWithNewOppsLastWeek: [],
      totals: { count: 0, amount: 0 }
    }
  }];
}

const header = rows[0].map(h => String(h || "").trim());
const dataRows = rows.slice(1);

console.log('📋 CSV Headers:', header);

// map rows to objects
const objects = dataRows.map(cols => {
  const o = {};
  for (let i = 0; i < header.length; i++) {
    o[header[i]] = cols[i] ?? "";
  }
  return o;
});

// ---------- normalize into opportunities ----------
const opportunities = [];
let totalAmount = 0;

for (const r of objects) {
  const accountName = getField(r, "Account Name", "Account", "ootb_opportunity_account_name");
  const oppName = getField(r, "Opportunity Name", "ootb_opportunity_name");
  const owner = getField(r, "Opportunity Owner (name)", "Opportunity Owner", "Owner", "ootb_opportunity_owner_name");
  const stage = getField(r, "Stage", "Current Stage", "ootb_opportunity_current_stage");
  const type = getField(r, "Opportunity Type", "Type", "ootb_opportunity_type");
  const createdDate = getField(r, "Creation Date", "Created Date", "ootb_opportunity_created_at");
  const closeDate = getField(r, "Close Date", "ootb_opportunity_close_date");

  // Your export includes "Amount (Converted)"
  const amount = toNumber(getField(r, "Amount (Converted)", "Amount (amount)", "Amount", "ootb_opportunity_converted_amount", "ootb_opportunity_amount"));

  // 🔥 CRITICAL: Extract Backstory ID for links
  const peopleaiIdRaw = getField(r, "People.ai Internal ID", "ootb_opportunity_people_internal_id", "Opportunity People.ai Internal ID");
  const peopleaiId = peopleaiIdRaw ? parseInt(peopleaiIdRaw, 10) : null;

  totalAmount += amount;

  opportunities.push({
    accountName,
    opportunityName: oppName,
    owner,
    amount,
    type,
    stage,
    createdDate,
    closeDate,
    peopleaiId,  // ✅ Now included!
    raw: r
  });
}

console.log(`✅ Parsed ${opportunities.length} opportunities`);
if (opportunities.length > 0) {
  console.log('Sample opp:', {
    name: opportunities[0].opportunityName,
    account: opportunities[0].accountName,
    amount: opportunities[0].amount,
    peopleaiId: opportunities[0].peopleaiId
  });
}

// accounts set
const accountsWithNewOppsLastWeek = Array.from(new Set(
  opportunities
    .map(o => String(o.accountName || "").trim())
    .filter(Boolean)
)).sort((a,b) => a.localeCompare(b));

return [{
  json: {
    opportunities,
    accountsWithNewOppsLastWeek,
    totals: {
      count: opportunities.length,
      amount: totalAmount
    }
  }
}];

// Format the complete weekly digest for Slack - CONCISE VERSION
const data = $input.first().json;

// Helper function to format currency
function formatCurrency(amount) {
  if (!amount || isNaN(amount)) return '`$0`';
  if (amount >= 1000000) {
    return `\`$${(amount / 1000000).toFixed(1)}M\``;
  }
  return `\`$${Math.round(amount / 1000)}K\``;
}

// Helper function to format date
function formatDate(dateStr) {
  if (!dateStr) return 'No date';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return 'Invalid date';
  const month = date.toLocaleDateString('en-US', { month: 'long' });
  const day = date.getDate();
  const year = date.getFullYear();
  return `${month} ${day}, ${year}`;
}

// Helper function to format close date as 16Dec25
function formatCloseDate(dateStr) {
  if (!dateStr) return 'No Date';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return 'Invalid';

  const day = date.getDate();
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const month = monthNames[date.getMonth()];
  const year = String(date.getFullYear()).slice(-2);

  return `${day}${month}${year}`;
}

// Helper function to truncate text
function truncate(text, maxLength) {
  if (!text) return '';
  if (text.length <= maxLength) return text;
  return text.substring(0, maxLength - 1) + '…';
}

// Helper function to parse days from HH:MM:SS format
function parseDaysInStage(daysStr) {
  if (!daysStr || daysStr === 'Unknown') return 0;

  // Handle HH:MM:SS format
  const parts = String(daysStr).split(':');
  if (parts.length === 3) {
    const hours = parseInt(parts[0]) || 0;
    const minutes = parseInt(parts[1]) || 0;
    const seconds = parseInt(parts[2]) || 0;
    const totalHours = hours + (minutes / 60) + (seconds / 3600);
    return Math.floor(totalHours / 24);
  }

  // Handle plain number
  const num = parseInt(daysStr);
  return isNaN(num) ? 0 : num;
}

// Helper function to create Backstory opportunity link
function createOppLink(peopleaiId, oppName) {
  if (!peopleaiId) return oppName;
  return `<https://app.people.ai/opportunity/${peopleaiId}|${oppName}>`;
}

// Helper function to create Backstory account link
function createAccountLink(peopleaiId, accountName) {
  if (!peopleaiId) return accountName;
  return `<https://app.people.ai/accounts/${peopleaiId}|${accountName}>`;
}

const weekStart = data.weekStart || formatDate(new Date());

// Build Slack message
let message = `*Weekly Opportunity Digest* 📊\n`;
message += `Last Week • ${weekStart}\n\n`;

// SECTION 1: NEW OPPORTUNITIES CREATED
const newOpps = data.newOppsCreated?.opportunities || [];
const totalNewOpps = newOpps.length;
const totalNewAmount = data.newOppsCreated?.totalAmount || newOpps.reduce((sum, o) => sum + (o.amount || 0), 0);

message += `🎯 *New Opportunities:* ${totalNewOpps} opps (${formatCurrency(totalNewAmount)})\n\n`;

if (totalNewOpps > 0) {
  // Group by type
  const grouped = {
    'New Business': [],
    'Upsell/Cross sell': [],
    'Customer Renewal': []
  };

  newOpps.forEach(opp => {
    const oppName = opp.opportunityName || opp.name || 'Unknown';
    const stage = opp.stage || 'Unknown';

    let category = 'New Business';
    if (oppName.toLowerCase().includes('upsell') || oppName.toLowerCase().includes('expansion')) {
      category = 'Upsell/Cross sell';
    } else if (oppName.toLowerCase().includes('renewal')) {
      category = 'Customer Renewal';
    }

    grouped[category].push(opp);
  });

  let counter = 1;

  // New Business
  if (grouped['New Business'].length > 0) {
    const nbTotal = grouped['New Business'].reduce((sum, o) => sum + (o.amount || 0), 0);
    message += `*New Business:* ${grouped['New Business'].length} opps (${formatCurrency(nbTotal)})\n`;
    grouped['New Business'].forEach(opp => {
      const oppLink = createOppLink(opp.peopleaiId, opp.opportunityName || opp.name);
      message += `${counter}. ${oppLink} • ${opp.accountName} • ${opp.owner} • ${formatCurrency(opp.amount)}\n`;
      counter++;
    });
    message += `\n`;
  }

  // Upsell/Cross sell
  if (grouped['Upsell/Cross sell'].length > 0) {
    const upsellTotal = grouped['Upsell/Cross sell'].reduce((sum, o) => sum + (o.amount || 0), 0);
    message += `*Upsell/Cross sell:* ${grouped['Upsell/Cross sell'].length} opps (${formatCurrency(upsellTotal)})\n`;
    grouped['Upsell/Cross sell'].forEach(opp => {
      const oppLink = createOppLink(opp.peopleaiId, opp.opportunityName || opp.name);
      message += `${counter}. ${oppLink} • ${opp.accountName} • ${opp.owner} • ${formatCurrency(opp.amount)}\n`;
      counter++;
    });
    message += `\n`;
  }

  // Customer Renewal
  if (grouped['Customer Renewal'].length > 0) {
    const renewalTotal = grouped['Customer Renewal'].reduce((sum, o) => sum + (o.amount || 0), 0);
    message += `*Customer Renewal:* ${grouped['Customer Renewal'].length} opps (${formatCurrency(renewalTotal)})\n`;
    grouped['Customer Renewal'].forEach(opp => {
      const oppLink = createOppLink(opp.peopleaiId, opp.opportunityName || opp.name);
      message += `${counter}. ${oppLink} • ${opp.accountName} • ${opp.owner} • ${formatCurrency(opp.amount)}\n`;
      counter++;
    });
    message += `\n`;
  }
} else {
  message += `_No new opportunities created last week_\n\n`;
}

message += `──────────────────────\n\n`;

// SECTION 2: 👻 GHOST OPPORTUNITIES
const buyingSignals = data.buyingSignals?.accounts || [];
message += `👻 *Ghost Opportunities*\n`;
message += `_Engaged accounts showing buying signals without CRM opportunities_\n\n`;

if (buyingSignals.length > 0) {
