function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false;
  let current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }
    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }
    current += c;
  }
  vals.push(current);
  return vals.map(v => v.trim());
}

